class Solution {
    public List<Integer> findSubstring(String s, String[] words) {
        List<Integer> result = new ArrayList<>();
        int n = s.length();
        int[] dp = new int[n + 1];
        Arrays.fill(dp, -1);

        for (String word : words) {
            for (int i = 0; i <= n; i++) {
                if (s.charAt(i) == word.charAt(0)) {
                    dp[i] = i;
                }
            }
        }

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (dp[i] != -1 && dp[j] != -1 && s.charAt(i) == s.charAt(j)) {
                    result.add(i + j);
                }
            }
        }

        return result;
    }
}
